Modified simulated annealing with three neighborhood operators (ship relocation, intra-route swap, inter-route exchange) selected probabilistically, each evaluated via delta-cost and accepted using Metropolis criterion at given temperature.}
func Optimization(dispatch Dispatch, temperature float64) Dispatch {
    if dispatch.AssignsLen < 1 {
        dispatch.RenewnTotalCost()
        return dispatch
    }
    const STEPS = 200
    currentBest := dispatch
    totalDelta := 0.0
    bestDeltaSeen := 0.0
    for step := 0; step < STEPS; step++ {
        r := rand.Float64()
        opType := 0
        if r < 0.4 && dispatch.AssignsLen > 1 {
            opType = 1
        } else if r < 0.7 && dispatch.AssignsLen > 1 {
            opType = 2
        } else if r < 1.0 {
            opType = 3
        }
        switch opType {
        case 1:
            a1 := rand.Intn(dispatch.AssignsLen)
            a2 := rand.Intn(dispatch.AssignsLen)
            if a1 == a2 {
                continue
            }
            origCost1 := dispatch.Assigns[a1].Cost
            origCost2 := dispatch.Assigns[a2].Cost
            id, ori, des := dispatch.Assigns[a1].RandShip()
            if id < 0 {
                continue
            }
            if !dispatch.Assigns[a2].AddShip(id, ori, des) {
                continue
            }
            dispatch.Assigns[a2].GenRoute()
            if dispatch.Assigns[a2].Cost < 0 {
                dispatch.Assigns[a2].RemoveShip(id)
                dispatch.Assigns[a2].GenRoute()
                continue
            }
            dispatch.Assigns[a1].RemoveShip(id)
            dispatch.Assigns[a1].GenRoute()
            if dispatch.Assigns[a1].Cost < 0 || dispatch.Assigns[a2].Cost < 0 {
                dispatch.Assigns[a1].AddShip(id, ori, des)
                dispatch.Assigns[a1].GenRoute()
                dispatch.Assigns[a2].RemoveShip(id)
                dispatch.Assigns[a2].GenRoute()
                continue
            }
            newCost := dispatch.Assigns[a1].Cost + dispatch.Assigns[a2].Cost
            oldCost := origCost1 + origCost2
            delta := newCost - oldCost
            if delta <= 0 || (temperature > 1e-9 && math.Exp(-delta/temperature) > rand.Float64()) {
                totalDelta += delta
                if totalDelta < bestDeltaSeen {
                    bestDeltaSeen = totalDelta
                    currentBest = dispatch
                }
            } else {
                dispatch.Assigns[a1].AddShip(id, ori, des)
                dispatch.Assigns[a1].GenRoute()
                dispatch.Assigns[a2].RemoveShip(id)
                dispatch.Assigns[a2].GenRoute()
            }
        case 2:
            a := rand.Intn(dispatch.AssignsLen)
            origCost := dispatch.Assigns[a].Cost
            id1, ori1, des1 := dispatch.Assigns[a].RandShip()
            if id1 < 0 {
                continue
            }
            id2, ori2, des2 := dispatch.Assigns[a].RandShip()
            if id2 < 0 || id1 == id2 {
                dispatch.Assigns[a].AddShip(id1, ori1, des1)
                dispatch.Assigns[a].GenRoute()
                continue
            }
            dispatch.Assigns[a].RemoveShip(id1)
            dispatch.Assigns[a].RemoveShip(id2)
            ok1 := dispatch.Assigns[a].AddShip(id1, ori2, des2)
            ok2 := dispatch.Assigns[a].AddShip(id2, ori1, des1)
            if !ok1 || !ok2 {
                dispatch.Assigns[a].RemoveShip(id1)
                dispatch.Assigns[a].RemoveShip(id2)
                dispatch.Assigns[a].AddShip(id1, ori1, des1)
                dispatch.Assigns[a].AddShip(id2, ori2, des2)
                dispatch.Assigns[a].GenRoute()
                continue
            }
            dispatch.Assigns[a].GenRoute()
            if dispatch.Assigns[a].Cost < 0 {
                dispatch.Assigns[a].RemoveShip(id1)
                dispatch.Assigns[a].RemoveShip(id2)
                dispatch.Assigns[a].AddShip(id1, ori1, des1)
                dispatch.Assigns[a].AddShip(id2, ori2, des2)
                dispatch.Assigns[a].GenRoute()
                continue
            }
            newCost := dispatch.Assigns[a].Cost
            delta := newCost - origCost
            if delta <= 0 || (temperature > 1e-9 && math.Exp(-delta/temperature) > rand.Float64()) {
                totalDelta += delta
                if totalDelta < bestDeltaSeen {
                    bestDeltaSeen = totalDelta
                    currentBest = dispatch
                }
            } else {
                dispatch.Assigns[a].RemoveShip(id1)
                dispatch.Assigns[a].RemoveShip(id2)
                dispatch.Assigns[a].AddShip(id1, ori1, des1)
                dispatch.Assigns[a].AddShip(id2, ori2, des2)
                dispatch.Assigns[a].GenRoute()
            }
        default:
            a := rand.Intn(dispatch.AssignsLen)
            origCost := dispatch.Assigns[a].Cost
            id, ori, des := dispatch.Assigns[a].RandShip()
            if id < 0 {
                continue
            }
            dispatch.Assigns[a].RemoveShip(id)
            dispatch.Assigns[a].GenRoute()
            if dispatch.Assigns[a].Cost < 0 {
                dispatch.Assigns[a].AddShip(id, ori, des)
                dispatch.Assigns[a].GenRoute()
                continue
            }
            ok := dispatch.Assigns[a].AddShip(id, ori, des)
            if !ok {
                dispatch.Assigns[a].GenRoute()
                continue
            }
            dispatch.Assigns[a].GenRoute()
            if dispatch.Assigns[a].Cost < 0 {
                dispatch.Assigns[a].RemoveShip(id)
                dispatch.Assigns[a].AddShip(id, ori, des)
                dispatch.Assigns[a].GenRoute()
                continue
            }
            newCost := dispatch.Assigns[a].Cost
            delta := newCost - origCost
            if delta <= 0 || (temperature > 1e-9 && math.Exp(-delta/temperature) > rand.Float64()) {
                totalDelta += delta
                if totalDelta < bestDeltaSeen {
                    bestDeltaSeen = totalDelta
                    currentBest = dispatch
                }
            } else {
                dispatch.Assigns[a].RemoveShip(id)
                dispatch.Assigns[a].AddShip(id, ori, des)
                dispatch.Assigns[a].GenRoute()
            }
        }
    }
    dispatch.RenewnTotalCost()
    currentBest.RenewnTotalCost()
    return currentBest

